/**
 * Pure validation functions for order operations.
 *
 * These validators contain no side effects and no database calls.
 * Services call these after performing any necessary data lookups.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate that an order has at least one item.
 * Throws if items array is empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Validate that the user exists for order creation.
 * The service performs the lookup; this function checks the result.
 */
export function validateOrderUser(user: User | undefined, userId: string): void {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate a status transition and throw if invalid.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate that an order exists.
 * The service performs the lookup; this function checks the result.
 */
export function validateOrderExists<T>(order: T | undefined, id: string): asserts order is T {
  if (!order) {
    throw new Error(`Order not found: ${id}`);
  }
}

/**
 * Pure validation functions for user operations.
 *
 * These validators contain no side effects and no database calls.
 * Services call these after performing any necessary data lookups.
 */

import type { User } from '../models/user.js';

/**
 * Validate that an email is not already taken.
 * The service performs the DB lookup; this function checks the result.
 */
export function validateEmailNotTaken(email: string, existingUser: User | undefined): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not in use by another user (for updates).
 * The service performs the DB lookup; this function checks the result.
 */
export function validateEmailNotInUse(email: string, existingUser: User | undefined): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

/**
 * Validate that a user exists.
 * The service performs the lookup; this function checks the result.
 */
export function validateUserExists(user: User | undefined, id: string): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${id}`);
  }
}

